// Pseudo-idempotent ingestion core
class IngestBuffer {
  constructor() { this.buffer = []; this.seen = new Set(); }
  enqueue(event) {
    const key = event.tenantId + ':' + event.seq;
    if (this.seen.has(key)) return;
    this.seen.add(key);
    this.buffer.push(event);
  }
  flush() { /* write to regional store; on failure keep in place for retry */ }
}
```

