// Ingest endpoint with idempotency and PII redaction
async function ingestEvent(rawEvent) {
  // 1. PII redaction: Hash user_id before storage
  const sanitizedEvent = {
    ...rawEvent,
    user_id_hash: hashUserId(rawEvent.user_id),
    user_id: undefined // Remove raw PII
  };

  // 2. Idempotency check for edit_apply events
  if (rawEvent.event_type === 'edit_apply') {
    const exists = await checkEventIdExists(rawEvent.event_id);
    if (exists) return { status: 'duplicate', event_id: rawEvent.event_id };
  }

  // 3. Route to tenant-specific Kafka partition
  await kafka.produce({
    topic: `tenant-${rawEvent.tenant_id}`,
    messages: [{ value: JSON.stringify(sanitizedEvent) }]
  });

  return { status: 'accepted', event_id: rawEvent.event_id };
}
```

