// Minimal utility: redact and hash user identifiers for privacy
function processEvent(rawEvent) {
  const { tenant_id, user_id, timestamp, event_type, ...rest } = rawEvent;

  return {
    tenant_id,
    user_id_hash: hashWithTenantSalt(tenant_id, user_id),
    timestamp: new Date(timestamp).toISOString(),
    event_type,
    ...redactPII(rest),
