// Kafka producer with quota enforcement
const producer = new KafkaProducer({
  'client.id': `telemetry-gateway-${region}`,
  'acks': 'all',
  'retries': 3
});

// Per-tenant quota checker
function checkQuota(tenantId, eventsThisMinute) {
  const limit = tenantQuotas.get(tenantId) || DEFAULT_QUOTA;
  if (eventsThisMinute >= limit) {
    return { allowed: false, sampled: true };
  }
  return { allowed: true, sampled: false };
}
```

