// Simple eligibility check for purge
function eligibleForPurge(record, policy, currentDate) {
  const byTenant = policy.tenant_id === record.tenant_id;
  const byRegion = policy.region === record.region;
  const ageDays = (currentDate - new Date(record.createdAt)) / (1000*60*60*24);
  const notOnHold = !record.hold_id || !policy.hold_ids.includes(record.hold_id);
  return byTenant && byRegion && ageDays > policy.retention_days && notOnHold;
}
