// Minimal per-tenant token bucket implementation
class TokenBucket {
  constructor(capacity, refillPerSec) {
    this.capacity = capacity;
    this.tokens = capacity;
    this._startRefill();
  }

  consume(amount = 1) {
    if (this.tokens >= amount) {
      this.tokens -= amount;
      return true;
    }
    return false;
  }

  _startRefill() {
    setInterval(() => {
      this.tokens = Math.min(this.capacity, this.tokens + this.refillPerSec);
    }, 1000);
  }
}
```

